#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int a[n];
        for (int i = 0; i < n; i++) {
            scanf("%d", &a[i]);
        }
        int dp[n];
        dp[0] = 1;
        for (int i = 1; i < n; i++) {
            dp[i] = 1;
            for (int j = 0; j < i; j++) {
                if (a[i] <= j) {
                    dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
                }
            }
        }
        int max = 0;
        for (int i = 0; i < n; i++) {
            max = (max > dp[i]) ? max : dp[i];
        }
        printf("%d\n", max);
    }
    return 0;
}

