                dp[i] = 1;
                for (int j = 0; j < i; j++) {
                    if (a[i] <= j) {
                        dp[i] = (dp[i] > dp[j] + 1) ? dp[i] : dp[j] + 1;
                    }
                }
            }
            int max = 0;
            for (int i = 0; i < n; i++) {
                max = (max > dp[i]) ? max : dp[i];
